var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우...... 대체 몇 번이나 설명해야 하지?","JPN":"ふう……いったい何回説明すればわかってくれるかしら？","ENG":"*Sigh* How many times do I have to explain it to you?","TWN":"呼……我還要說多少次？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말하지만 전기란 건 사용하면 돈을 내야 해.","JPN":"もう一度言うけど、電気というのは使ったらお金がかかるの。","ENG":"Electricity costs money.","TWN":"我再說一遍，用電必須交電費。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 우리 회사는 돈이 별로 없어.","JPN":"だけど、うちの会社はお金の余裕がないの。","ENG":"And our company doesn't have much money.","TWN":"但我們公司沒有多少資金。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 멋대로 전기를 끌어다 쓰지 말라고 했잖니?","JPN":"だから勝手に電気を横取りして使わないでって\\n言ったわよね？","ENG":"I told you not to waste electricity, didn't I?","TWN":"所以你不能這樣隨意用電，我說多少次了？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오늘로만 벌써 세 번째 정전이야. 경고는 줄 만큼 줬다고 생각하는데?","JPN":"今日だけでもう3回目の停電よ？　十分注意した\\nはずなのに。","ENG":"That was the third blackout today. How many more warnings do you need?","TWN":"這已經是第三次停電了，我到底還要警告多少次？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"하지만 고장 난 로봇을 고쳐주려면 그 정도 전력은 필요해.","JPN":"でも、壊れたロボットを修理するにはそれくらいの\\n電力が必要なの。","ENG":"But I need electricity to repair broken robots.","TWN":"但要修復損壞的機器人必須用到電力啊。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"게다가 여긴 도움이 필요한 로봇들이 엄청나게 많은걸!","JPN":"それに、ここは助けが必要なロボットだらけだから\\n仕方ないもん！","ENG":"And this place is filled with broken robots.","TWN":"而且這裡有很多需要幫助的機器人！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"망가진 로봇도 가족이니까 당연히 고쳐줘야 하잖아?","JPN":"壊れたロボットも家族なんだから、当然治して\\nあげるべきよね？","ENG":"They're also our family. We have to fix them.","TWN":"損壞的機器人也是家人，所以必須幫它們修理！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"넌 잘 모르겠지만 회사라는 곳은 수지타산이라는 제 1원칙을 지켜야 굴러가는 곳이야.","JPN":"あなたはまだわからないだろうけど、会社というものは\\n費用対効果を第一に考えないと維持できないの。","ENG":"You may not understand this, but companies exist to make profits.","TWN":"你可能還不瞭解，公司的第一原則是收支平衡。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"싸구려 청소로봇을 수리하기 위해 한 달치 전기요금을 지불하는 회사는 어디에도 없어.","JPN":"安価な掃除ロボットを修理するために、一か月分の\\n電気料金をかける会社なんてどこにもないわよ。","ENG":"No company can survive by paying a month's worth of electricity on a cheap cleaning robot.","TWN":"沒有任何公司會為了 一個廉價的清潔機器人支付一整個月的電費。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네가 얼마나 대단한진 모르겠지만, 계속 이런 식으로 굴면 전원을 꺼버릴 거야.","JPN":"あなたがどれだけすごいかはわからないけど、このままなら\\n電源を切ってしまいますからね？","ENG":"I don't care how important you are to the Boss. Keep misbehaving like this, and I'm going to turn off your power.","TWN":"我不知道你有多大能耐，但你如果繼續這樣，我只能關掉你的電源。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠니?","JPN":"わかってくれるかしら？","ENG":"Is that understood?","TWN":"知道了嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으으으......","JPN":"むうう……","ENG":"Ugh...","TWN":"唔……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"치사해! 치사해!","JPN":"ケチ！　ケチ！　副社長のケチ！","ENG":"It's not fair! It's just not fair!","TWN":"好卑鄙！好卑鄙！"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"치사한 사람이야! 아빠가 부사장님 혼내줘!","JPN":"ケチ臭いったらありゃしない！　パパからも\\n副社長に何か言ってよ！","ENG":"She's a cheapskate! Daddy, punish her!","TWN":"太卑鄙了！爸爸快罵罵副總！"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......회사를 위해 결단을 내리셔야 합니다, 사장님.","JPN":"……会社のために決断が必要です、社長。","ENG":"Boss, you have to make the decision for your company.","TWN":"……老闆，你必須為公司做出決定。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당장 저 골칫거리 깡통의 전원을 끄고 어디 창고에라도 처박아두시죠.","JPN":"今すぐあの厄介なボロ缶の電源を切って、どこかの\\n倉庫にでもぶちこんではいかがでしょう。","ENG":"Turn off that troublesome tin can right now and put it in a corner of a warehouse somewhere.","TWN":"快把這煩人的破銅爛鐵的電源關掉，扔進倉庫裡。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"골칫거리 깡통?!","JPN":"厄介なボロ缶だって！？","ENG":"Troublesome tin can?","TWN":"煩人的破銅爛鐵？！"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"말했어! 그렇게 말했겠다!","JPN":"言ったね？　間違いなくそう言ったよね？！","ENG":"Did you just call me a troublesome tin can?","TWN":"你敢！你敢這麼說！"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......둘 다 진정하게.","JPN":"……二人とも落ち着きなさい。","ENG":"Calm down, both of you.","TWN":"……你們兩個都冷靜一下。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 어린애가 장난친 걸 가지고 그렇게 정색할 필요는 없지 않나?","JPN":"君も子どものおままごとにそこまでムキになること\\nないじゃないか？","ENG":"She played with some robots, so what? You shouldn't take it so seriously.","TWN":"小孩子開玩笑而已，你何必發這麼大火？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전기세 정도야 어떻게든......","JPN":"電気代くらい、どうにでも……","ENG":"We can afford electricity—","TWN":"不就是電費而已嘛……"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 한가한 소리는 재정보고서나 읽어보신 후에 하시죠.","JPN":"そんな悠長な話、まずは財政報告書を確認してから\\nしてほしいですわね。","ENG":"I suggest you read my financial report before completing that sentence.","TWN":"請你先看過財務報表後，再來說這種話。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이대로 가다간 저 제멋대로인 녀석 때문에 다음 달 급여 지급에 중차대한 문제가......","JPN":"このままだとこのワガママ娘のせいで、来月の\\n給与支払いに重大な問題が……","ENG":"At this rate, we won't even have enough money to pay our employees for the next month—","TWN":"這樣下去，下個月就無法正常支付薪資了……"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"음? 비상연락망?","JPN":"あら？　非常連絡網からの着信？","ENG":"Mm? An emergency call?","TWN":"嗯？緊急聯絡網？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"급한 연락인가 보군요. 잠시 후에 다시 이야기하시죠.","JPN":"緊急連絡みたいですね。後ほど改めて話しましょう。","ENG":"It must be urgent. We'll talk later.","TWN":"可能是有急事，待會再說吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......네, 알겠습니다. 검토 후에 다시 연락 드리죠.","JPN":"……はい、承知しました。検討の上、折り返します。","ENG":"... Okay, I see. We'll get back to you as soon as we can.","TWN":"……是，好的。我稍後再聯繫你。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"곤란한 일이 생겼군요.","JPN":"困ったことが。","ENG":"We've got a problem.","TWN":"遇到麻煩了。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭔가? 설마 전기세 체납 징수라도 들어온다던가?","JPN":"何だい？　まさか電気代の滞納徴収とか？","ENG":"What is it? Are they going to take legal actions to collect the unpaid electricity bills?","TWN":"怎麼？有人要來徵收拖欠的電費嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"차라리 그게 낫겠네요.","JPN":"そっちのほうがマシかも知れません。","ENG":"Worse than that.","TWN":"比這個嚴重多了。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정기 순찰 임무를 수행하던 타이탄이 해적들과의 전투에 휘말려 나포되었다고 합니다.","JPN":"定期見回り任務を遂行していたタイタンが、\\n海賊の戦闘に巻き込まれてさらわれたそうです。","ENG":"Titan got entangled with pirates while on routine patrol duty. Now, it's in their hands.","TWN":"執行定期巡邏任務的泰坦被捲進海盜的戰鬥中，然後被他們抓走了。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당시 현장에 있었던 호송 대원들이 타이탄의 구조 작전을 요청해 왔습니다.","JPN":"その時現場にいた搬送隊員がタイタンの救助作戦を\\n要請してきました。","ENG":"The convoy which was at the scene has called for Titan's rescue.","TWN":"現場的護送隊員請求我們救援泰坦。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......할아버지가?","JPN":"……おじいちゃんが？","ENG":"Grandpa?","TWN":"……爺爺？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"타이탄이 해적에게 나포 당했다고?","JPN":"タイタンが海賊にさらわれた？","ENG":"Titan is captured by a bunch of pirates?","TWN":"泰坦被海盜抓了？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"별일이로군. 아직 완전한 상태가 아니라고는 해도 어떻게 일개 해적들에게 당한 거지?","JPN":"不思議だな。まだ完全復活していないとはいえ、\\nたかが海賊にやられるなんて。","ENG":"That's a first. Even if he's not fully himself at this moment, he's far too strong to let that happen.","TWN":"真奇怪。雖然它還不是巔峰狀態，但也不至於被區區海盜打敗呀？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"적들 중에 특이한 능력을 가진 카운터가 있었다고 합니다.","JPN":"敵の中に変わった能力を持つカウンターがいたそうです。","ENG":"One of them is a special Counter,","TWN":"敵人中有一個擁有特殊能力的制裁者。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기계장치의 인공지능을 교란하는 능력인 것 같은데......","JPN":"機械装置の人工知能をかく乱する能力のようですが……","ENG":"with the ability to disrupt AI functions, it seems.","TWN":"他好像能擾亂機械裝置的人工智慧……"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"호위로 대동했던 퓨처 앳 워의 전투 병기들의 통제권도 모두 빼앗겼다고 하는군요.","JPN":"ガードにつけていたフューチャーアットウォーの\\n戦闘兵器の統制権もすべて奪われたとか。","ENG":"The convoy even lost control of the Future-at-War machines that it had with it.","TWN":"負責護衛的天啟兵器的戰鬥兵器也全部喪失了控制權。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"타이탄도 인공지능 시스템을 제외하면 대부분 퓨처 앳 워의 기술력으로 단순복원을 한 것뿐이니, 마찬가지로 당할 수 밖에 없었던 거겠죠.","JPN":"タイタンも人工知能システムを除けば、ほぼ\\nフューチャーアットウォーの技術力で復元しただけなので、\\n同様にやられるしかなかったのでしょう。","ENG":"Titan, except for its AI system, is a simple replica produced by Future-at-War. It fared no better than the others.","TWN":"畢竟泰坦除了人工智慧系統，其他部分大多是用天啟兵器的技術簡單復原的，被敵人抓捕也不足為奇。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"곤란하게 됐군. 그거 매입하느라 비용이 꽤 많이 들지 않았나?","JPN":"まいったなー。　あれを買い付けるのに相当な\\n費用がかかっただろう？","ENG":"This is not good. Didn't we spend a fortune on him?","TWN":"這可麻煩了，當時不是花很多錢才買下它的嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다. 할부금도 아직 까마득하게 남아있죠.","JPN":"はい、未払い金もまだまだ残っています。","ENG":"We did. In fact, we have years left on the loan we took out.","TWN":"是，分期款還剩很多期沒付。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"감히 저희 회사의 재산을 가로채려고 하다니 목숨이 열두 개쯤 되는 녀석들인가 보군요.","JPN":"我が社の資産を横取りしようとするなんて、よっぽどの\\n命知らずですね。","ENG":"Those pirates are suicidal, daring to steal our asset.","TWN":"竟敢對我們公司的資產下手，真是一群不自量力的傢伙。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"차라리 잘 됐습니다.","JPN":"ちょうど良かったです。","ENG":"Maybe it's better this way.","TWN":"反倒是好事。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 답답함과 분노를 해소할 겸, 제가 직접 가서 당장 박살을...... 음?","JPN":"この鬱憤を晴らすためにも私が出向いて撲滅を……\\nあら？","ENG":"I could use a fight to release my pent-up anger and frustration—mm?","TWN":"我要親自去解決他們，以解我心中的鬱悶和憤怒……嗯？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......꼬마 아가씨가 보이지 않는군요. 어디로 갔죠?","JPN":"……おチビちゃんが見当たりませんね。\\nどこに行ったかしら？","ENG":"The little girl is gone. Where did she go?","TWN":"……那個小妹妹怎麼不見了，她去哪裡了？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시그마? 방금 전까지도 옆에 있었던 것 같은데......?","JPN":"シグマのことか？　ついさっきまでそばにいたと思うが……","ENG":"Sigma? She was next to us just a moment ago.","TWN":"西格瑪？剛剛還在這裡的呀……？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 설마?","JPN":"まさか……","ENG":"Uh-oh.","TWN":"啊，難道……？"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리 대화를 엿듣고 있었나 보네요.","JPN":"私たちの会話を盗み聞きしていたようですね。","ENG":"She must have heard us.","TWN":"她好像聽到了我們的對話。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아, 정말 골칫거리라니까요.","JPN":"はあ、本当に厄介な子だわ……","ENG":"Gosh, she's a handful.","TWN":"啊，真是個麻煩製造者。"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};